(function(){function ready(fn){if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",fn)}else{fn()}}ready(function(){var wrapper=document.querySelector(".author__urls-wrapper");if(!wrapper)return;var button=wrapper.querySelector("button");var links=wrapper.querySelector(".author__urls");if(!button||!links)return;function isButtonVisible(){return window.getComputedStyle(button).display!=="none"}function sync(){if(isButtonVisible()){links.style.display="none";button.setAttribute("aria-expanded","false");button.classList.remove("open")}else{links.style.display="block";button.setAttribute("aria-expanded","true")}}button.addEventListener("click",function(){var visible=links.style.display==="block";links.style.display=visible?"none":"block";button.setAttribute("aria-expanded",visible?"false":"true");button.classList.toggle("open",!visible)});window.addEventListener("resize",sync);sync()})})();
